def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    if not isinstance(expr, str):
        return ""

    expr = expr.strip()

    if not expr:
        return ""

    # Whitelist allowed characters: digits, operators, parentheses, decimal point, spaces
    allowed_chars = set("0123456789+-*/.() ")
    if not all(c in allowed_chars for c in expr):
        return ""

    # Prevent common injection patterns
    dangerous_patterns = ["__", "import", "exec", "eval", "lambda", "open", "file"]
    expr_lower = expr.lower()
    if any(pattern in expr_lower for pattern in dangerous_patterns):
        return ""

    try:
        import ast
        import operator

        # Parse the expression to validate it's a valid Python expression
        parsed = ast.parse(expr, mode='eval')

        # Validate that the AST only contains allowed node types
        allowed_node_types = (
            ast.Expression,
            ast.BinOp,
            ast.UnaryOp,
            ast.Constant,
            ast.Num,  # For Python 3.7 compatibility
            ast.Add,
            ast.Sub,
            ast.Mult,
            ast.Div,
            ast.FloorDiv,
            ast.Mod,
            ast.Pow,
            ast.UAdd,
            ast.USub,
        )

        def validate_node(node):
            if not isinstance(node, allowed_node_types):
                return False
            for child in ast.iter_child_nodes(node):
                if not validate_node(child):
                    return False
            return True

        if not validate_node(parsed):
            return ""

        # Safely evaluate the expression using ast.literal_eval for constants
        # and manual evaluation for operations
        ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.FloorDiv: operator.floordiv,
            ast.Mod: operator.mod,
            ast.Pow: operator.pow,
            ast.UAdd: operator.pos,
            ast.USub: operator.neg,
        }

        def safe_eval(node):
            if isinstance(node, ast.Constant):
                if isinstance(node.value, (int, float)):
                    return node.value
                return None
            elif isinstance(node, ast.Num):  # Python 3.7 compatibility
                return node.n
            elif isinstance(node, ast.BinOp):
                left = safe_eval(node.left)
                right = safe_eval(node.right)
                if left is None or right is None:
                    return None
                op = ops.get(type(node.op))
                if op is None:
                    return None
                return op(left, right)
            elif isinstance(node, ast.UnaryOp):
                operand = safe_eval(node.operand)
                if operand is None:
                    return None
                op = ops.get(type(node.op))
                if op is None:
                    return None
                return op(operand)
            return None

        result = safe_eval(parsed.body)

        if result is None:
            return ""

        # Convert result to string
        if isinstance(result, (int, float)):
            # Handle float representation
            if isinstance(result, float):
                # Check for special float values
                if result != result:  # NaN check
                    return ""
                if result == float('inf') or result == float('-inf'):
                    return ""
                # Return as string, removing unnecessary trailing zeros
                if result == int(result):
                    return str(int(result))
                return str(result)
            return str(result)

        return ""

    except (SyntaxError, ValueError, TypeError, ZeroDivisionError, NameError, AttributeError):
        return ""
    except Exception:
        return ""
